'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { ArrowLeft, Image as ImageIcon, Send, Eye, EyeOff } from 'lucide-react';
import Sidebar from '@/components/layout/Sidebar';
import MobileNav from '@/components/layout/MobileNav';
import { mockTopics } from '@/data/topics';
import { useAuth } from '@/contexts/AuthContext';

export default function ArticleCreatePage() {
  const router = useRouter();
  const { currentUser } = useAuth();
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [excerpt, setExcerpt] = useState('');
  const [topicSlug, setTopicSlug] = useState('');
  const [coverUrl, setCoverUrl] = useState('');
  const [isPreview, setIsPreview] = useState(false);
  const [published, setPublished] = useState(false);

  if (!currentUser || (currentUser.role !== 'editor' && currentUser.role !== 'admin')) {
    router.push('/');
    return null;
  }

  const handlePublish = () => {
    if (!title.trim() || !content.trim() || !topicSlug) return;
    setPublished(true);
    setTimeout(() => router.push('/'), 1500);
  };

  const selectedTopic = mockTopics.find((t) => t.slug === topicSlug);

  if (published) {
    return (
      <div className="min-h-screen flex items-center justify-center" style={{ background: '#000' }}>
        <motion.div
          initial={{ scale: 0.8, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          className="text-center"
        >
          <motion.div
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            transition={{ delay: 0.2, type: 'spring' }}
            className="w-20 h-20 rounded-full mx-auto mb-4 flex items-center justify-center"
            style={{ background: 'rgba(0,186,124,0.1)' }}
          >
            <Send className="w-10 h-10" style={{ color: '#00BA7C' }} />
          </motion.div>
          <h2 className="text-xl font-bold mb-2" style={{ color: '#E7E9EA' }}>Bài viết đã được đăng!</h2>
          <p className="text-sm" style={{ color: '#71767B' }}>Đang chuyển về trang chủ...</p>
        </motion.div>
      </div>
    );
  }

  return (
    <div className="min-h-screen" style={{ background: '#000' }}>
      <Sidebar />
      <main className="lg:ml-[275px] min-h-screen max-w-3xl">
        {/* Header */}
        <div className="sticky top-0 z-30 flex items-center justify-between px-4 py-3 border-b"
          style={{ background: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(12px)', borderColor: '#2F3336' }}
        >
          <div className="flex items-center gap-4">
            <button onClick={() => router.back()} className="p-2 rounded-full hover:bg-white/10" style={{ color: '#E7E9EA' }}>
              <ArrowLeft className="w-5 h-5" />
            </button>
            <h1 className="text-lg font-bold" style={{ color: '#E7E9EA' }}>✍️ Viết bài mới</h1>
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setIsPreview(!isPreview)}
              className="px-3 py-1.5 rounded-lg text-sm flex items-center gap-1.5 border"
              style={{ borderColor: '#2F3336', color: '#71767B' }}
            >
              {isPreview ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              {isPreview ? 'Sửa' : 'Xem trước'}
            </button>
            <motion.button
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              onClick={handlePublish}
              disabled={!title.trim() || !content.trim() || !topicSlug}
              className="px-4 py-1.5 rounded-full text-sm font-semibold text-white disabled:opacity-40"
              style={{ background: '#F97316' }}
            >
              Đăng bài
            </motion.button>
          </div>
        </div>

        <div className="p-4">
          {isPreview ? (
            /* Preview Mode */
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-4">
              {coverUrl && (
                <div className="rounded-2xl overflow-hidden border" style={{ borderColor: '#2F3336' }}>
                  <img src={coverUrl} alt="Cover" className="w-full h-[300px] object-cover" />
                </div>
              )}
              {selectedTopic && (
                <span className="inline-block px-3 py-1 rounded-full text-sm"
                  style={{ background: `${selectedTopic.color}20`, color: selectedTopic.color }}
                >
                  {selectedTopic.icon} {selectedTopic.name}
                </span>
              )}
              <h1 className="text-2xl font-bold" style={{ color: '#E7E9EA' }}>{title || 'Tiêu đề bài viết'}</h1>
              <p style={{ color: '#71767B' }}>{excerpt || 'Mô tả ngắn...'}</p>
              <div className="prose" dangerouslySetInnerHTML={{ __html: content || '<p>Nội dung bài viết...</p>' }} />
            </motion.div>
          ) : (
            /* Edit Mode */
            <div className="space-y-4">
              {/* Cover image URL */}
              <div>
                <label className="text-sm font-medium mb-1.5 block" style={{ color: '#71767B' }}>
                  <ImageIcon className="w-4 h-4 inline mr-1" /> Ảnh bìa (URL)
                </label>
                <input
                  type="url"
                  value={coverUrl}
                  onChange={(e) => setCoverUrl(e.target.value)}
                  placeholder="https://images.unsplash.com/..."
                  className="w-full px-4 py-2.5 rounded-xl border text-sm focus:outline-none"
                  style={{ background: '#16181C', borderColor: '#2F3336', color: '#E7E9EA' }}
                  onFocus={(e) => (e.target.style.borderColor = '#F97316')}
                  onBlur={(e) => (e.target.style.borderColor = '#2F3336')}
                />
                {coverUrl && (
                  <div className="mt-2 rounded-xl overflow-hidden border" style={{ borderColor: '#2F3336' }}>
                    <img src={coverUrl} alt="Preview" className="w-full h-[150px] object-cover" />
                  </div>
                )}
              </div>

              {/* Topic */}
              <div>
                <label className="text-sm font-medium mb-1.5 block" style={{ color: '#71767B' }}>Chủ đề</label>
                <div className="flex flex-wrap gap-2">
                  {mockTopics.map((topic) => (
                    <button
                      key={topic.slug}
                      onClick={() => setTopicSlug(topic.slug)}
                      className="px-3 py-1.5 rounded-full text-sm font-medium border transition-all"
                      style={{
                        borderColor: topicSlug === topic.slug ? topic.color : '#2F3336',
                        background: topicSlug === topic.slug ? `${topic.color}20` : 'transparent',
                        color: topicSlug === topic.slug ? topic.color : '#71767B',
                      }}
                    >
                      {topic.icon} {topic.name}
                    </button>
                  ))}
                </div>
              </div>

              {/* Title */}
              <div>
                <input
                  type="text"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="Tiêu đề bài viết"
                  className="w-full text-2xl font-bold border-none focus:outline-none"
                  style={{ background: 'transparent', color: '#E7E9EA' }}
                />
              </div>

              {/* Excerpt */}
              <div>
                <textarea
                  value={excerpt}
                  onChange={(e) => setExcerpt(e.target.value)}
                  placeholder="Mô tả ngắn (hiển thị trên feed)..."
                  rows={2}
                  className="w-full px-4 py-2.5 rounded-xl border text-sm resize-none focus:outline-none"
                  style={{ background: '#16181C', borderColor: '#2F3336', color: '#E7E9EA' }}
                  onFocus={(e) => (e.target.style.borderColor = '#F97316')}
                  onBlur={(e) => (e.target.style.borderColor = '#2F3336')}
                />
              </div>

              {/* Content - Simple textarea for MVP (TipTap can be added with npm install) */}
              <div>
                <label className="text-sm font-medium mb-1.5 block" style={{ color: '#71767B' }}>
                  Nội dung (hỗ trợ HTML)
                </label>
                <textarea
                  value={content}
                  onChange={(e) => setContent(e.target.value)}
                  placeholder="<h2>Tiêu đề phần</h2>&#10;<p>Nội dung bài viết...</p>&#10;<ul><li>Điểm 1</li><li>Điểm 2</li></ul>"
                  rows={15}
                  className="w-full px-4 py-3 rounded-xl border text-sm resize-none focus:outline-none font-mono"
                  style={{ background: '#16181C', borderColor: '#2F3336', color: '#E7E9EA', lineHeight: '1.8' }}
                  onFocus={(e) => (e.target.style.borderColor = '#F97316')}
                  onBlur={(e) => (e.target.style.borderColor = '#2F3336')}
                />
              </div>
            </div>
          )}
        </div>
      </main>
      <MobileNav />
    </div>
  );
}
